/* ==========================================================================
   Buy Property Services - Main Custom Stylesheet
   Shopify Dawn Theme Fork | UK Property Services Marketplace
   ========================================================================== */

/* --------------------------------------------------------------------------
   1. Google Fonts Import
   -------------------------------------------------------------------------- */
@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700;800&display=swap');

/* --------------------------------------------------------------------------
   2. CSS Custom Properties (Brand Palette)
   -------------------------------------------------------------------------- */
:root {
  /* Brand Colors */
  --color-green-dark: #1A4D2E;
  --color-green-dark-rgb: 26, 77, 46;
  --color-orange: #E8922A;
  --color-orange-rgb: 232, 146, 42;
  --color-olive: #8FB339;
  --color-olive-rgb: 143, 179, 57;
  --color-cream: #F5F0E1;
  --color-cream-rgb: 245, 240, 225;
  --color-tan: #C4B699;
  --color-tan-rgb: 196, 182, 153;
  --color-white: #FFFFFF;
  --color-dark: #1A1A1A;

  /* Semantic Aliases */
  --color-primary: var(--color-green-dark);
  --color-accent: var(--color-orange);
  --color-secondary: var(--color-olive);
  --color-background: var(--color-cream);
  --color-border: var(--color-tan);
  --color-text: var(--color-dark);

  /* Typography */
  --font-family: 'Poppins', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;
  --font-weight-extrabold: 800;

  /* Spacing */
  --section-padding-mobile: 3rem 1.25rem;
  --section-padding-tablet: 4rem 2rem;
  --section-padding-desktop: 5rem 3rem;

  /* Transitions */
  --transition-base: 0.3s ease;

  /* Shadows */
  --shadow-sm: 0 2px 8px rgba(0, 0, 0, 0.06);
  --shadow-md: 0 4px 16px rgba(0, 0, 0, 0.08);
  --shadow-lg: 0 8px 32px rgba(0, 0, 0, 0.12);
  --shadow-glow-green: 0 0 20px rgba(var(--color-green-dark-rgb), 0.3);
  --shadow-glow-orange: 0 0 20px rgba(var(--color-orange-rgb), 0.3);

  /* Border Radius */
  --radius-sm: 6px;
  --radius-md: 10px;
  --radius-lg: 16px;
  --radius-full: 50%;
}

/* --------------------------------------------------------------------------
   3. Dawn Theme Global Overrides
   -------------------------------------------------------------------------- */
html {
  scroll-behavior: smooth;
  font-size: 16px;
}

body,
.shopify-section,
.shopify-section-group-header-group,
.shopify-section-group-footer-group {
  font-family: var(--font-family);
  color: var(--color-text);
}

body {
  background-color: var(--color-cream);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* Override Dawn CSS variables where safe */
:root,
:root .color-background-1 {
  --color-foreground: 26, 26, 26;
  --color-background: 245, 240, 225;
  --gradient-background: var(--color-cream);
}

h1, h2, h3, h4, h5, h6,
.h0, .h1, .h2, .h3, .h4, .h5, .h6 {
  font-family: var(--font-family);
  font-weight: var(--font-weight-bold);
  color: var(--color-dark);
  line-height: 1.2;
}

a {
  transition: color var(--transition-base), opacity var(--transition-base);
}

img {
  max-width: 100%;
  height: auto;
}

/* --------------------------------------------------------------------------
   4. Header Styles
   -------------------------------------------------------------------------- */
.bps-header,
.section-header {
  background-color: var(--color-green-dark);
  color: var(--color-white);
  position: sticky;
  top: 0;
  z-index: 1000;
  transition: background-color var(--transition-base), box-shadow var(--transition-base);
}

.bps-header a,
.section-header .header__heading-link,
.section-header .header__menu-item,
.section-header .list-menu__item--link {
  color: var(--color-white);
  text-decoration: none;
}

.bps-header a:hover,
.section-header .header__menu-item:hover,
.section-header .list-menu__item--link:hover {
  color: var(--color-orange);
}

/* Header icon buttons (cart, search, menu) */
.section-header .header__icon,
.section-header .header__icon .icon {
  color: var(--color-white);
  fill: var(--color-white);
}

.section-header .header__icon:hover {
  color: var(--color-orange);
}

/* Cart count badge */
.section-header .cart-count-bubble {
  background-color: var(--color-orange);
  color: var(--color-white);
}

/* Transparent header on homepage hero */
.header--transparent {
  background-color: transparent;
  position: absolute;
  width: 100%;
}

.header--transparent.header--scrolled {
  background-color: var(--color-green-dark);
  position: sticky;
  box-shadow: 0 2px 12px rgba(0, 0, 0, 0.15);
}

/* Mobile menu drawer */
.menu-drawer {
  background-color: var(--color-green-dark);
  color: var(--color-white);
}

.menu-drawer a,
.menu-drawer .menu-drawer__menu-item {
  color: var(--color-white);
  font-family: var(--font-family);
}

.menu-drawer a:hover,
.menu-drawer .menu-drawer__menu-item:hover {
  color: var(--color-orange);
}

.menu-drawer__close-button .icon {
  color: var(--color-white);
}

/* --------------------------------------------------------------------------
   5. Hero Banner
   -------------------------------------------------------------------------- */
.hero-banner {
  position: relative;
  width: 100%;
  height: 70vh;
  min-height: 480px;
  display: flex;
  align-items: center;
  justify-content: center;
  text-align: center;
  overflow: hidden;
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
}

.hero-banner::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(
    to top,
    rgba(0, 0, 0, 0.65) 0%,
    rgba(0, 0, 0, 0.25) 50%,
    rgba(0, 0, 0, 0.1) 100%
  );
  z-index: 1;
}

.hero-banner__content {
  position: relative;
  z-index: 2;
  max-width: 720px;
  padding: 1.5rem;
}

.hero-banner__heading {
  font-size: clamp(1.75rem, 5vw, 3.5rem);
  font-weight: var(--font-weight-extrabold);
  color: var(--color-white);
  text-shadow: 0 2px 12px rgba(0, 0, 0, 0.4);
  margin-bottom: 1rem;
  line-height: 1.15;
}

.hero-banner__subheading {
  font-size: clamp(0.95rem, 2vw, 1.25rem);
  color: rgba(255, 255, 255, 0.9);
  font-weight: var(--font-weight-regular);
  margin-bottom: 2rem;
  text-shadow: 0 1px 6px rgba(0, 0, 0, 0.3);
}

/* Toggle buttons: I am Selling / I am Renting */
.hero-banner__toggle {
  display: inline-flex;
  gap: 0;
  border-radius: var(--radius-lg);
  overflow: hidden;
  border: 2px solid var(--color-white);
  margin-bottom: 1.5rem;
}

.hero-banner__toggle-btn {
  padding: 0.85rem 1.75rem;
  font-family: var(--font-family);
  font-size: 1rem;
  font-weight: var(--font-weight-semibold);
  border: none;
  cursor: pointer;
  transition: background-color var(--transition-base), color var(--transition-base);
  background-color: transparent;
  color: var(--color-white);
  min-height: 54px;
}

.hero-banner__toggle-btn:hover {
  background-color: rgba(255, 255, 255, 0.15);
}

.hero-banner__toggle-btn.is-active {
  background-color: var(--color-orange);
  color: var(--color-white);
}

.hero-banner__cta {
  display: inline-block;
  margin-top: 0.5rem;
}

@media (min-width: 990px) {
  .hero-banner {
    height: 100vh;
    min-height: 600px;
  }
}

/* --------------------------------------------------------------------------
   6. Service Grid
   -------------------------------------------------------------------------- */
.service-grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 1.25rem;
  padding: 0;
}

.service-grid__card {
  background: rgba(255, 255, 255, 0.85);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border: 1px solid rgba(var(--color-tan-rgb), 0.4);
  border-radius: var(--radius-lg);
  padding: 1.75rem 1.5rem;
  text-align: center;
  transition:
    transform var(--transition-base),
    box-shadow var(--transition-base),
    border-color var(--transition-base);
  box-shadow: var(--shadow-sm);
}

.service-grid__card:hover {
  transform: translateY(-8px);
  box-shadow: var(--shadow-lg), 0 0 24px rgba(var(--color-green-dark-rgb), 0.12);
  border-color: var(--color-olive);
}

.service-grid__icon {
  width: 64px;
  height: 64px;
  margin: 0 auto 1rem;
  display: flex;
  align-items: center;
  justify-content: center;
  background-color: rgba(var(--color-green-dark-rgb), 0.08);
  border-radius: var(--radius-full);
}

.service-grid__icon img,
.service-grid__icon svg {
  width: 32px;
  height: 32px;
}

.service-grid__title {
  font-size: 1.125rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-dark);
  margin-bottom: 0.5rem;
}

.service-grid__price {
  font-size: 0.9rem;
  color: var(--color-orange);
  font-weight: var(--font-weight-semibold);
  margin-bottom: 1.25rem;
}

.service-grid__price span {
  font-size: 1.35rem;
  font-weight: var(--font-weight-bold);
}

.service-grid__cta {
  display: block;
  width: 100%;
  min-height: 54px;
}

@media (min-width: 750px) {
  .service-grid {
    grid-template-columns: repeat(2, 1fr);
    gap: 1.5rem;
  }
}

@media (min-width: 990px) {
  .service-grid {
    grid-template-columns: repeat(3, 1fr);
    gap: 2rem;
  }

  .service-grid__cta {
    width: auto;
    display: inline-block;
  }
}

/* --------------------------------------------------------------------------
   7. Trust Bar
   -------------------------------------------------------------------------- */
.trust-bar {
  display: flex;
  gap: 1rem;
  overflow-x: auto;
  scroll-snap-type: x mandatory;
  -webkit-overflow-scrolling: touch;
  padding-bottom: 0.5rem;
  scrollbar-width: thin;
}

.trust-bar::-webkit-scrollbar {
  height: 4px;
}

.trust-bar::-webkit-scrollbar-thumb {
  background: var(--color-tan);
  border-radius: 4px;
}

.trust-bar__item {
  flex: 0 0 auto;
  min-width: 200px;
  scroll-snap-align: start;
  background: var(--color-white);
  border-radius: var(--radius-md);
  padding: 1.25rem 1.5rem;
  text-align: center;
  box-shadow: var(--shadow-sm);
}

.trust-bar__stat {
  font-size: 1.75rem;
  font-weight: var(--font-weight-bold);
  color: var(--color-green-dark);
  line-height: 1;
  margin-bottom: 0.35rem;
}

.trust-bar__label {
  font-size: 0.85rem;
  color: var(--color-dark);
  opacity: 0.7;
}

.trust-bar__stars {
  color: var(--color-orange);
  font-size: 1.1rem;
  letter-spacing: 2px;
  margin-bottom: 0.35rem;
}

@media (min-width: 750px) {
  .trust-bar {
    overflow-x: visible;
    flex-wrap: wrap;
    justify-content: center;
  }

  .trust-bar__item {
    flex: 0 1 auto;
    min-width: 180px;
  }
}

/* --------------------------------------------------------------------------
   8. Process Timeline
   -------------------------------------------------------------------------- */
.process-timeline {
  position: relative;
  display: flex;
  flex-direction: column;
  gap: 2rem;
  padding-left: 2.5rem;
}

/* Vertical connecting line (mobile) */
.process-timeline::before {
  content: '';
  position: absolute;
  left: 15px;
  top: 0;
  bottom: 0;
  width: 3px;
  background-color: var(--color-tan);
  border-radius: 2px;
}

.process-timeline__step {
  position: relative;
  padding: 0;
}

.process-timeline__number {
  position: absolute;
  left: -2.5rem;
  top: 0;
  width: 32px;
  height: 32px;
  background-color: var(--color-green-dark);
  color: var(--color-white);
  border-radius: var(--radius-full);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.85rem;
  font-weight: var(--font-weight-bold);
  z-index: 1;
}

.process-timeline__icon {
  font-size: 1.5rem;
  margin-bottom: 0.5rem;
}

.process-timeline__title {
  font-size: 1rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-dark);
  margin-bottom: 0.25rem;
}

.process-timeline__desc {
  font-size: 0.875rem;
  color: var(--color-dark);
  opacity: 0.7;
  line-height: 1.5;
}

@media (min-width: 990px) {
  .process-timeline {
    flex-direction: row;
    padding-left: 0;
    gap: 0;
    justify-content: space-between;
    align-items: flex-start;
  }

  /* Horizontal connecting line (desktop) */
  .process-timeline::before {
    left: 0;
    right: 0;
    top: 15px;
    bottom: auto;
    width: auto;
    height: 3px;
  }

  .process-timeline__step {
    flex: 1;
    text-align: center;
    padding: 3rem 1rem 0;
  }

  .process-timeline__number {
    left: 50%;
    top: 0;
    transform: translateX(-50%);
  }
}

/* --------------------------------------------------------------------------
   9. Service Card Snippet (.card-service)
   -------------------------------------------------------------------------- */
.card-service {
  background: rgba(255, 255, 255, 0.85);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border: 1px solid rgba(var(--color-tan-rgb), 0.4);
  border-radius: var(--radius-lg);
  overflow: hidden;
  transition:
    transform var(--transition-base),
    box-shadow var(--transition-base),
    border-color var(--transition-base);
  box-shadow: var(--shadow-sm);
}

.card-service:hover {
  transform: translateY(-4px);
  box-shadow: var(--shadow-md);
  border-color: var(--color-olive);
  animation: pulse-glow 2s ease-in-out infinite;
}

.card-service__image {
  width: 100%;
  aspect-ratio: 16 / 10;
  object-fit: cover;
}

.card-service__body {
  padding: 1.25rem 1.5rem;
}

.card-service__title {
  font-size: 1.05rem;
  font-weight: var(--font-weight-semibold);
  margin-bottom: 0.5rem;
}

.card-service__price-badge {
  display: inline-block;
  background-color: var(--color-orange);
  color: var(--color-white);
  padding: 0.3rem 0.85rem;
  border-radius: var(--radius-sm);
  font-size: 0.85rem;
  font-weight: var(--font-weight-bold);
  margin-bottom: 0.75rem;
}

.card-service__price-badge--starting {
  background-color: rgba(var(--color-orange-rgb), 0.12);
  color: var(--color-orange);
}

.card-service__desc {
  font-size: 0.875rem;
  color: var(--color-dark);
  opacity: 0.7;
  line-height: 1.5;
  margin-bottom: 1rem;
}

.card-service__actions {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.card-service__actions .btn-primary {
  width: 100%;
  min-height: 54px;
}

@media (min-width: 750px) {
  .card-service__actions {
    flex-direction: row;
  }

  .card-service__actions .btn-primary {
    width: auto;
  }
}

/* --------------------------------------------------------------------------
   10. Animations
   -------------------------------------------------------------------------- */
@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(30px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes pulse-glow {
  0%, 100% {
    box-shadow: var(--shadow-md), 0 0 0 0 rgba(var(--color-green-dark-rgb), 0);
  }
  50% {
    box-shadow: var(--shadow-md), 0 0 18px 2px rgba(var(--color-green-dark-rgb), 0.15);
  }
}

@keyframes float-orb {
  0%, 100% {
    transform: translateY(0) translateX(0);
  }
  25% {
    transform: translateY(-15px) translateX(8px);
  }
  50% {
    transform: translateY(-8px) translateX(-5px);
  }
  75% {
    transform: translateY(-20px) translateX(3px);
  }
}

/* Scroll reveal */
.reveal-on-scroll {
  opacity: 0;
  transform: translateY(30px);
  transition: opacity 0.6s ease, transform 0.6s ease;
}

.reveal-on-scroll.is-visible {
  opacity: 1;
  transform: translateY(0);
}

/* Decorative floating orb */
.floating-orb {
  position: absolute;
  border-radius: var(--radius-full);
  opacity: 0.15;
  pointer-events: none;
  animation: float-orb 8s ease-in-out infinite;
}

/* Respect reduced motion */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }

  .reveal-on-scroll {
    opacity: 1;
    transform: none;
  }
}

/* --------------------------------------------------------------------------
   11. Buttons
   -------------------------------------------------------------------------- */
.btn-primary {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  background-color: var(--color-orange);
  color: var(--color-white);
  font-family: var(--font-family);
  font-size: 0.95rem;
  font-weight: var(--font-weight-semibold);
  padding: 0.8rem 1.75rem;
  border: none;
  border-radius: var(--radius-lg);
  cursor: pointer;
  text-decoration: none;
  min-height: 54px;
  transition:
    background-color var(--transition-base),
    transform var(--transition-base),
    box-shadow var(--transition-base);
}

.btn-primary:hover {
  background-color: #d17e1f;
  transform: translateY(-2px);
  box-shadow: var(--shadow-glow-orange);
  color: var(--color-white);
}

.btn-primary:active {
  transform: translateY(0);
}

.btn-secondary {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  background-color: transparent;
  color: var(--color-green-dark);
  font-family: var(--font-family);
  font-size: 0.95rem;
  font-weight: var(--font-weight-semibold);
  padding: 0.8rem 1.75rem;
  border: 2px solid var(--color-green-dark);
  border-radius: var(--radius-lg);
  cursor: pointer;
  text-decoration: none;
  min-height: 54px;
  transition:
    background-color var(--transition-base),
    color var(--transition-base),
    transform var(--transition-base);
}

.btn-secondary:hover {
  background-color: var(--color-green-dark);
  color: var(--color-white);
  transform: translateY(-2px);
}

.btn-secondary:active {
  transform: translateY(0);
}

.btn-add-bundle {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.4rem;
  background-color: rgba(var(--color-olive-rgb), 0.12);
  color: var(--color-olive);
  font-family: var(--font-family);
  font-size: 0.85rem;
  font-weight: var(--font-weight-semibold);
  padding: 0.6rem 1.25rem;
  border: 1px solid var(--color-olive);
  border-radius: var(--radius-md);
  cursor: pointer;
  text-decoration: none;
  transition: background-color var(--transition-base), color var(--transition-base);
}

.btn-add-bundle:hover {
  background-color: var(--color-olive);
  color: var(--color-white);
}

/* Mobile: full-width buttons */
@media (max-width: 749px) {
  .btn-primary,
  .btn-secondary,
  .btn-add-bundle {
    width: 100%;
  }
}

/* --------------------------------------------------------------------------
   12. Product / Service Page Styles
   -------------------------------------------------------------------------- */

/* Accordion / Collapsible Content */
.bps-accordion {
  border: 1px solid var(--color-tan);
  border-radius: var(--radius-md);
  overflow: hidden;
  margin-bottom: 0.75rem;
}

.bps-accordion__trigger {
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--color-white);
  border: none;
  padding: 1rem 1.25rem;
  font-family: var(--font-family);
  font-size: 1rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-dark);
  cursor: pointer;
  transition: background-color var(--transition-base);
}

.bps-accordion__trigger:hover {
  background-color: rgba(var(--color-cream-rgb), 0.6);
}

.bps-accordion__trigger[aria-expanded="true"] {
  border-bottom: 1px solid var(--color-tan);
}

.bps-accordion__icon {
  width: 20px;
  height: 20px;
  transition: transform var(--transition-base);
}

.bps-accordion__trigger[aria-expanded="true"] .bps-accordion__icon {
  transform: rotate(180deg);
}

.bps-accordion__content {
  padding: 1rem 1.25rem;
  font-size: 0.9rem;
  line-height: 1.65;
  color: var(--color-dark);
  background: var(--color-white);
}

/* Product page process timeline */
.product-timeline {
  background: rgba(var(--color-cream-rgb), 0.5);
  border-radius: var(--radius-lg);
  padding: 1.5rem;
  margin: 1.5rem 0;
}

/* Property address input */
.bps-address-input {
  width: 100%;
  padding: 0.85rem 1rem;
  border: 2px solid var(--color-tan);
  border-radius: var(--radius-md);
  font-family: var(--font-family);
  font-size: 0.95rem;
  color: var(--color-dark);
  background: var(--color-white);
  transition: border-color var(--transition-base), box-shadow var(--transition-base);
}

.bps-address-input:focus {
  outline: none;
  border-color: var(--color-green-dark);
  box-shadow: 0 0 0 3px rgba(var(--color-green-dark-rgb), 0.12);
}

.bps-address-input::placeholder {
  color: var(--color-tan);
}

/* Starting from price display */
.bps-price-starting {
  display: flex;
  align-items: baseline;
  gap: 0.4rem;
  margin: 0.75rem 0;
}

.bps-price-starting__label {
  font-size: 0.8rem;
  color: var(--color-dark);
  opacity: 0.6;
  font-weight: var(--font-weight-regular);
}

.bps-price-starting__amount {
  font-size: 1.75rem;
  font-weight: var(--font-weight-bold);
  color: var(--color-orange);
}

/* --------------------------------------------------------------------------
   13. Footer
   -------------------------------------------------------------------------- */
.bps-footer,
.section-footer .footer {
  background-color: var(--color-green-dark);
  color: var(--color-white);
}

.bps-footer a,
.section-footer .footer a {
  color: rgba(255, 255, 255, 0.8);
  text-decoration: none;
  transition: color var(--transition-base);
}

.bps-footer a:hover,
.section-footer .footer a:hover {
  color: var(--color-orange);
}

.section-footer .footer__title {
  color: var(--color-white);
  font-weight: var(--font-weight-semibold);
}

.section-footer .footer__content-bottom {
  border-top: 1px solid rgba(255, 255, 255, 0.15);
}

.section-footer .copyright__content,
.section-footer .footer__content-bottom-wrapper a {
  color: rgba(255, 255, 255, 0.5);
}

/* Social icons */
.bps-footer__social a,
.section-footer .footer__list-social .list-social__link {
  color: var(--color-white);
  transition: color var(--transition-base), transform var(--transition-base);
}

.bps-footer__social a:hover,
.section-footer .footer__list-social .list-social__link:hover {
  color: var(--color-orange);
  transform: translateY(-2px);
}

.section-footer .footer__column {
  color: rgba(255, 255, 255, 0.8);
}

/* --------------------------------------------------------------------------
   14. Utility Classes
   -------------------------------------------------------------------------- */

/* Text */
.text-accent {
  color: var(--color-orange);
}

.text-green {
  color: var(--color-green-dark);
}

.text-white {
  color: var(--color-white);
}

.text-center {
  text-align: center;
}

/* Backgrounds */
.bg-cream {
  background-color: var(--color-cream);
}

.bg-green-dark {
  background-color: var(--color-green-dark);
  color: var(--color-white);
}

.bg-white {
  background-color: var(--color-white);
}

/* Glassmorphism Card */
.glass-card {
  background: rgba(255, 255, 255, 0.85);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border: 1px solid rgba(var(--color-tan-rgb), 0.4);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-sm);
}

/* Section padding (responsive) */
.section-padding {
  padding: var(--section-padding-mobile);
}

@media (min-width: 750px) {
  .section-padding {
    padding: var(--section-padding-tablet);
  }
}

@media (min-width: 990px) {
  .section-padding {
    padding: var(--section-padding-desktop);
  }
}

/* Section headings */
.section-heading {
  font-size: clamp(1.5rem, 4vw, 2.25rem);
  font-weight: var(--font-weight-bold);
  text-align: center;
  margin-bottom: 0.5rem;
}

.section-subheading {
  font-size: clamp(0.9rem, 2vw, 1.05rem);
  text-align: center;
  color: var(--color-dark);
  opacity: 0.65;
  margin-bottom: 2.5rem;
  max-width: 600px;
  margin-left: auto;
  margin-right: auto;
}

/* --------------------------------------------------------------------------
   15. Mobile Sticky Bottom CTA Bar
   -------------------------------------------------------------------------- */
.sticky-bottom-cta {
  display: none;
}

@media (max-width: 749px) {
  .sticky-bottom-cta {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.75rem;
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    z-index: 999;
    background: var(--color-white);
    padding: 0.75rem 1rem;
    border-top: 1px solid var(--color-tan);
    box-shadow: 0 -4px 16px rgba(0, 0, 0, 0.08);
  }

  .sticky-bottom-cta__price {
    font-size: 1.15rem;
    font-weight: var(--font-weight-bold);
    color: var(--color-orange);
    white-space: nowrap;
  }

  .sticky-bottom-cta__price small {
    display: block;
    font-size: 0.7rem;
    font-weight: var(--font-weight-regular);
    color: var(--color-dark);
    opacity: 0.6;
  }

  .sticky-bottom-cta .btn-primary {
    flex: 1;
    min-height: 48px;
  }

  /* Prevent body content hiding behind sticky bar */
  body.has-sticky-cta {
    padding-bottom: 80px;
  }
}

/* --------------------------------------------------------------------------
   16. Dawn Component Overrides (Scoped)
   -------------------------------------------------------------------------- */

/* Dawn product form button */
.product-form__submit.button {
  background-color: var(--color-orange);
  color: var(--color-white);
  font-family: var(--font-family);
  font-weight: var(--font-weight-semibold);
  border-radius: var(--radius-lg);
  min-height: 54px;
  transition: background-color var(--transition-base);
}

.product-form__submit.button:hover {
  background-color: #d17e1f;
}

/* Dawn collection card */
.card-wrapper .card {
  border-radius: var(--radius-md);
  overflow: hidden;
}

/* Dawn newsletter section */
.newsletter-form__field-wrapper .field__input {
  border-radius: var(--radius-md);
  font-family: var(--font-family);
}

.newsletter-form__button {
  background-color: var(--color-orange);
  border-radius: var(--radius-md);
}

/* Dawn pagination */
.pagination__item--current {
  background-color: var(--color-green-dark);
  color: var(--color-white);
}

/* --------------------------------------------------------------------------
   17. Wide Breakpoint Enhancements
   -------------------------------------------------------------------------- */
@media (min-width: 1200px) {
  .page-width {
    max-width: 1320px;
    padding-left: 3rem;
    padding-right: 3rem;
  }

  .service-grid {
    gap: 2.5rem;
  }

  .hero-banner__heading {
    font-size: 3.75rem;
  }
}
